	FOREIGN KEY (`cluster_id`) REFERENCES `failure_clusters`(`id`) ON UPDATE no action ON DELETE cascade
);

CREATE UNIQUE INDEX `idx_failure_diagnoses_cluster_id` ON `failure_diagnoses` (`cluster_id`);
CREATE TABLE `files` (
